<template>
  <div>
    <table
      width="100%"
      border="0"
      cellpadding="0"
      cellspacing="0"
      bordercolor="#E8F6F7"
      bgcolor="#FFFFFF"
      class="BK"
    >
      <tr>
        <td height="42" width="40%" align="right" bgcolor="#0A7E81" class="BK2">
          <span class="STYLE2">开始日期：</span>
        </td>
        <td class="BK3" width="60%">
          <input id="startDate" @click="selectDate(1)" readonly="readonly" />
        </td>
      </tr>
      <tr>
        <td height="42" align="right" bgcolor="#0A7E81" class="BK2">
          <span class="STYLE2">结束日期：</span>
        </td>
        <td class="BK3">
          <!--<input type="date" id="endDate">-->
          <input id="endDate" @click="selectDate(2)" readonly="readonly" />
        </td>
      </tr>
    </table>
    <br />
    <table width="100%" border="0" cellspacing="0" cellpadding="0">
      <tr>
        <!--<td width="50%">&nbsp;</td>-->
        <td width="12%">
          <table
            width="130"
            border="1"
            cellpadding="0"
            cellspacing="0"
            bordercolor="#FFFFFF"
          >
            <tr
              @click="getRencentMoreDayTraffic(2)"
              style="background-color: #0a7e81"
              id="tr2"
            >
              <td height="50" align="center">
                <span class="STYLE4">wifi流量统计</span>
              </td>
            </tr>
          </table>
        </td>
        <td width="12%">
          <table
            width="130"
            border="1"
            cellpadding="0"
            cellspacing="0"
            bordercolor="#FFFFFF"
          >
            <tr
              @click="getRencentMoreDayTraffic(3)"
              style="background-color: #0a7e81"
              id="tr3"
            >
              <td height="50" align="center">
                <span class="STYLE4">移动流量统计</span>
              </td>
            </tr>
          </table>
        </td>
        <td width="12%">
          <table
            width="80"
            border="1"
            cellpadding="0"
            cellspacing="0"
            bordercolor="#FFFFFF"
            bgcolor="#0A7E81"
            style="display: none"
          >
            <tr>
              <td height="50" align="center">
                <span class="STYLE4" @click="clearData()">清除</span>
              </td>
            </tr>
          </table>
        </td>
      </tr>
    </table>
    <br />
    <div
      id="chart1"
      style="margin-top: 5px; margin-left: 0px; width: 100%; height: 240px"
    ></div>
  </div>
</template>

<script>
export default {
  name: "netTrafficStat", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      isFirstIn: false,
      limitCount: 5,
      mType: 2,
      isSelectedWifi: false,
      isSelectedMobile: false,
      timerId: null,
      restoreUseTime: 60 * 1000,
    };
  },
  computed: {},
  created() {
    this.isFirstIn = true;
  },
  mounted() {
    document.addEventListener("deviceready", this.onDeviceReady, false);
  },
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    onDeviceReady() {
      console.log("1onDeviceReady()-->start");
      ready = true;

      console.log("2onDeviceReady()--end");
      getRencentMoreDayTraffic(2);
      //	window.addEventListener("trafficupdated", onTrafficUpdated, false);
    },

    onTrafficUpdated(info) {
      console.log("trafficUpdated()-->info=" + JSON.stringify(info));
      this.successMoreCallback(info);
    },
    getOneDayTraffic() {
      console.log("getOneDayTraffic()-->start");
      if (!ready) {
        console.log("Cordova is not ready,return");
        return;
      }
      var day = $("#oneday").val();
      console.log("getOneDayTraffic()-->oneday=" + day);
      mam.navigator.netTrafficStat.getOneDayTraffic(
        successCallback,
        errorCallback,
        day
      );

      //执行成功回调
      //这边参数表示扫描成功后返回的字符串
      function successCallback(msg) {
        console.log("successCallback() msg:" + JSON.stringify(msg));
        $("#textarea").val(JSON.stringify(msg));
      }

      //执行失败回调[扫描失败，暂不退出界面未做处理]
      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },

    getOneMonthTraffic() {
      console.log("getOneDayTraffic()-->start");
      if (!ready) {
        console.log("Cordova is not ready,return");
        return;
      }
      var onemonthsatrt = $("#onemonthsatrt").val();
      var onemonthend = $("#onemonthend").val();
      console.log(
        "getOneDayTraffic()-->onemonthsatrt=" +
          onemonthsatrt +
          " onemonthend=" +
          onemonthend
      );
      mam.navigator.netTrafficStat.getOneMonthTraffic(
        successCallback,
        errorCallback,
        onemonthsatrt,
        onemonthend
      );

      //执行成功回调
      //这边参数表示扫描成功后返回的字符串
      function successCallback(msg) {
        console.log("successCallback() msg:" + JSON.stringify(msg));
        $("#textarea").val(JSON.stringify(msg));
      }

      //执行失败回调[扫描失败，暂不退出界面未做处理]
      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },
    getRencentMoreDayTraffic(type) {
      console.log("getRencentMoreDayTraffic()-->start --type==" + type);
      this.mType = type;
      if (!ready) {
        console.log("Cordova is not ready,return");
        return;
      }
      //var daycount=$('#daycount').val();
      //var endday=$('#endday').val();
      var startDate = $("#startDate").val();
      var endDate = $("#endDate").val();

      if (!this.isFirstIn) {
        if (!startDate || !endDate) {
          //alert("日期不能为空");
          mam.navigator.notification.alert(
            "日期不能为空",
            function () {},
            "提示"
          );
          return;
        }
      }
      this.isFirstIn = false;

      if (type == 2 && this.isSelectedWifi) {
        return;
      }
      if (type == 3 && this.isSelectedMobile) {
        return;
      }

      if (startDate && endDate) {
        var check = this.compareDate(startDate, endDate);
        if (!check) {
          //alert("日期选择错误");
          mam.navigator.notification.alert(
            "日期选择错误",
            function () {},
            "提示"
          );
          return;
        }
        if (1 == check) {
          //	alert("支持5天以内查询");
          mam.navigator.notification.alert(
            "支持5天以内查询",
            function () {},
            "提示"
          );
          return;
        }

        if (2 == type) {
          document.getElementById("tr3").style.backgroundColor = "#0A7E81";
          document.getElementById("tr2").style.backgroundColor = "#aaaaaa";
          this.isSelectedWifi = true;
          this.isSelectedMobile = false;
        } else if (3 == type) {
          document.getElementById("tr2").style.backgroundColor = "#0A7E81";
          document.getElementById("tr3").style.backgroundColor = "#aaaaaa";
          this.isSelectedMobile = true;
          this.isSelectedWifi = false;
        }
        if (this.timerId) {
          clearTimeout(this.timerId);
        }
        this.timerId = setTimeout(function () {
          document.getElementById("tr2").style.backgroundColor = "#0A7E81";
          document.getElementById("tr3").style.backgroundColor = "#0A7E81";
          this.isSelectedWifi = false;
          this.isSelectedMobile = false;
        }, this.restoreUseTime);
      }

      //var  daycount=4;
      //var  endday="2014-05-15 00:00:09";
      console.log(
        "getRencentMoreDayTraffic()-->startDate=" +
          startDate +
          " endDate=" +
          endDate
      );
      mam.navigator.netTrafficStat.getRencentMoreDayTraffic(
        this.successMoreCallback,
        this.errorMoreCallback,
        startDate,
        endDate,
        type
      );
    },

    compareDate(str1, str2) {
      var arr1 = str1.split("-");
      var date1 = new Date(arr1[0], parseInt(arr1[1]) - 1, arr1[2]);

      //var str2 = "2009-8-4";
      var arr2 = str2.split("-");
      var date2 = new Date(arr2[0], parseInt(arr2[1]) - 1, arr2[2]);
      if (date1 >= date2) {
        return 0;
      }
      var result = this.calcDays(date1, date2);

      if (result >= this.limitCount) {
        return 1;
      }
      return 2;
    },

    calcDays(startDate, endDate) {
      var result = Math.floor(
        (endDate.getTime() - startDate.getTime()) / (1000 * 3600 * 24)
      );
      return result;
    },
    //执行成功回调
    //这边参数表示扫描成功后返回的字符串
    successMoreCallback(msg) {
      console.log("successCallback() msg:" + JSON.stringify(msg));

      if (!msg || msg[0].length == 0) {
        $("#chart1").html("没有数据");
        return;
      }
      //$('#textarea').val(JSON.stringify(msg));
      var line1 = msg[0]; //子统计1数据
      var line2 = msg[1]; //子统计2数据

      var ticks = msg[2]; //['05-15', '05-14', '05-13', '05-12', '05-11'];
      var title = "";
      if (2 == this.mType) {
        title = "wifi流量统计图(Mb)";
      } else if (3 == this.mType) {
        title = "移动流量统计图(Mb)";
      }

      $("#chart1").html("");
      var isAnim = !$.jqplot.use_excanvas;
      //showJqplot();
      //获取设备类型
      var deviceModel = device.model;

      if (deviceModel.indexOf("HN3-U01") > -1) {
        //alert(deviceModel);
        isAnim = false;
      }

      var plot1 = $.jqplot("chart1", [line1, line2], {
        title: title,
        legend: { show: true, location: "ne" }, //, ,xoffset: -3,yoffset: -3placement: 'outside' 提示工具栏--show：是否显示,location: 显示位置 (e:东,w:西,s:南,n:北,nw:西北,ne:东北,sw:西南,se:东南)
        series: [{ label: "下载" }, { label: "上传" }], //提示工具栏
        animate: isAnim, //!$.jqplot.use_excanvas,
        seriesDefaults: {
          pointLabels: { show: true, formatString: "%.2f" },
          showMarker: true, // 是否强调显示图中的数据节点
          renderer: $.jqplot.BarRenderer, //使用柱状图表示
          rendererOptions: {
            barMargin: 15, //柱状体组之间间隔
          },
        },
        axes: {
          xaxis: {
            renderer: $.jqplot.CategoryAxisRenderer, //x轴绘制方式
            //label: 'X',
            ticks: ticks,
            labelRenderer: $.jqplot.CanvasAxisLabelRenderer,
            tickOptions: {
              //fontFamily: 'Georgia',
              fontSize: "8px",
              // angle: -30
            },
          },
          yaxis: {
            min: 0, //y轴最小值
            tickInterval: 5, //网格线间隔大小
            labelRenderer: $.jqplot.CanvasAxisLabelRenderer,
            show: true,
            tickOptions: {
              //fontFamily: 'Georgia',
              fontSize: "7px",
            },
          },
        },
      });
    },

    //执行失败回调[扫描失败，暂不退出界面未做处理]
    errorMoreCallback(msg) {
      console.log("errorCallback() msg:" + msg);
    },

    clearData() {
      $("#startDate").val("");
      $("#endDate").val("");
    },

    selectDate(dateType) {
      mam.navigator.netTrafficStat.showDateDialog(
        successCallback,
        errorCallback
      );
      //执行成功回调
      //这边参数表示扫描成功后返回的字符串
      function successCallback(msg) {
        console.log("successCallback() msg:" + msg);
        if (1 == dateType) {
          $("#startDate").val(msg);
        } else if (2 == dateType) {
          $("#endDate").val(msg);
        }
      }

      //执行失败回调[扫描失败，暂不退出界面未做处理]
      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },
  },
};
</script>
<style lang='css' scoped>
/* @import url(); 引入css类 */
</style>